import java.util.*;class Solution{static String s;static Map<String,Integer>D=new HashMap<>();static Map<Integer,Long>C=new HashMap<>();static String[]M={".-","-...","-.-.","-..",".","..-.","--.","....","..",".---","-.-",".-..","--","-.","---",".--.","--.-",".-.","...","-","..-","...-",".--","-..-","-.--","--.."};static long f(int i){if(i==s.length())return 1;if(C.containsKey(i))return C.get(i);long r=0;for(var e:D.entrySet()){var k=e.getKey();if(s.startsWith(k,i))r+=e.getValue()*f(i+k.length());}C.put(i,r);return r;}public static void main(String[]a){var sc=new Scanner(System.in);s=sc.next();int n=sc.nextInt();for(;n-->0;){var w=sc.next();var m=new StringBuilder();for(var c:w.toCharArray())m.append(M[c-'A']);D.merge(m.toString(),1,Integer::sum);}System.out.println(f(0));}}